@module paramAutomation  src=paramAutomation.lua  loc=449  sha=31b8f53  mode=chunk
@deps cm, facade

# Invariants & contracts
  @invariant  automation bus is 126 — 127 is wiring's parking bus, wiring allocates 0..125
  @invariant  authored (chan,lane) codes are track-unique across takes; bus codes project-unique

# Shapes
  @shape  binding = { busCode=int, trackGuid=str, fxGuid=str, param=int, scale=num, offset=num, label=str }
  @shape  trackSpec = { filter={ {src=code,dst=code},... }, listen={ {code,fxGuid,param,scale,offset},... }, sends={dstGuid,...} }
  @shape  paramFrecency (cm global) = { [fxIdent] = { n=int, params={ [name]={s=num,n0=int} } } }

# Imports
  @require util = 'util'  @ 17
      @contract  apply() is a full-project idempotent reconcile; mirror-matching tracks are untouched

# Private state
  @state AUTO_BUS = 126  @ 20
  @state CC_IDENT = 'JS:Continuum CC'  @ 21
  @state SLOTS = 16  @ 22
  @state META_PEXT = 'P_EXT:ctm_paramAuto'  @ 23
  @state TOP_LANE = 119  @ 24   -- 120..127 are channel-mode messages
  @state P_VALUE, P_SRC, P_DST, P_LISTEN = 0, 16, 32, 48  @ 27
  @state pa = {}  @ 29
  @state DECAY = 0.9  @ 297
  @state paramCache = {}  @ 299   -- [fxGuid] = { count, params, gen, sorted }
  @state frecencyGen = 0  @ 300   -- bumped on every frecency write; stales sorted caches

# Private functions
  -- REAPER lookups
  @fn trackByGuid(guid)  @ 33
  @fn fxIndexByGuid(track, guid)  @ 40
  @fn resolveFx(trackGuid, fxGuid)  @ 46
  @fn ccNodeIndex(track)  @ 53
      -- fx_ident for a JSFX is the bare Effects-relative path (cf. routingManager fxIdentAt)
  @fn eachTake(visit)  @ 63
  @fn boundTrack()  @ 73
  -- Gather + desired specs
  @fn gatherBindings()  @ 80
  -- Apply
  @fn readMirror(track)  @ 137
  @fn writeMirror(track, spec)  @ 144
  @fn setPlink(track, fxIdx, param, ccIdx, slot, scale, offset)  @ 148
  @fn clearPlink(track, fxIdx, param)  @ 160
  @fn writeBanks(track, ccIdx, spec)  @ 166
  @fn reconcileAutoSends(track, dstGuids)  @ 180
      -- Ours by signature: midi-only send whose src bus is the automation bus.
      -- Encoding mirrors routingManager createSend/readSendChans (bits 14/22, +1-biased).
  @fn applyTrack(track, spec, mirror)  @ 209
  -- Allocation
  @fn usedLanes(srcTrack, chan)  @ 254
      -- Authored lanes are track-unique across takes (the filter bank is shared per
      -- track): used = bound lanes, user cc columns, and event-bearing ccs on the
      -- channel, across every take on the track.
  @fn allocLane(srcTrack, chan)  @ 273
  @fn allocBusCode()  @ 280
  -- Frecency + param cache
  @fn fxIdentAt(track, fxIdx)  @ 302

# Public API (pa:*)
  @api pa.computeDesired(bindings)  @ 101
      -- Pure: bindings -> { [trackGuid] = trackSpec }. Pooled duplicates collapse
      -- via the seen-keys; slot order is sorted for a stable REAPER image.
  @api pa.frecencyOrder(params, fxScores)  @ 308
      @contract  pure, stable: decayed score desc, then param index; fxScores may be nil
  @api pa:apply()  @ 326
      @contract  no-op (and no undo point) when every track's mirror already matches
  @api pa:automate(chan, target)  @ 343
      @contract  chan is the tracker's 1-based channel; returns the allocated cc lane, or nil + reason
  @api pa:unautomate(chan, lane)  @ 362
  @api pa:binding(chan, lane)  @ 371
  @api pa:targets()  @ 377
      @contract  palette rows from the wiring facade's cone walk; {} without a take or wiring
  @api pa:params(trackGuid, fxGuid)  @ 385
      @contract  cached per fxGuid (param-count change invalidates); frecency-hot params first
  @api pa:bumpFrecency(trackGuid, fxGuid, paramName)  @ 408
      @contract  advances the ident's use counter; the param's score decays to it, then +1
  @api pa:floatFx(trackGuid, fxGuid)  @ 425
      @contract  floats the fx ui; true only when pa floated it — caller owns popping it down
  @api pa:unfloatFx(trackGuid, fxGuid)  @ 432
  @api pa:lastTouched()  @ 438
      @contract  last-touched track-fx param as guids + name; nil for take/container/input fx

